//vip.opstream11.com/20220403/9069_ef3c7dfb/index.m3u8"},{"name":"43","slug":"43","filename":"Vòng Quay Hạnh Phúc - All Is Well - Tập 43","link_embed":"https://vip.opstream11.com/share/5f5d472067f77b5c88f69f1bcfda1e08","link_m3u8":"https://vip.opstream11.com/20220403/9068_f902a352/index.m3u8"},{"name":"44","slug":"44","filename":"Vòng Quay Hạnh Phúc - All Is Well - Tập 44","link_embed":"https://vip.opstream11.com/share/74c4481c34e417ac39d1de6b4f854c4f","link_m3u8":"https://vip.opstream11.com/20220403/9067_da825646/index.m3u8"},{"name":"45","slug":"45","filename":"Vòng Quay Hạnh Phúc - All Is Well - Tập 45","link_embed":"https://vip.opstream11.com/share/79d37fb2893b428f7ea4ed3b07a84096","link_m3u8":"https://vip.opstream11.com/20220403/9066_fc18d2ac/index.m3u8"},{"name":"46","slug":"46","filename":"Vòng Quay Hạnh Phúc - All Is Well - Tập 46","link_embed":"https://vip.opstream11.com/share/7806689d934e610d660caf5536fea0b2","link_m3u8":"https://vip.opstream11.com/20220403/9070_2b236fdd/index.m3u8"}]}],"time":"43 phút/tập","description":"<p>Bộ phim được chuyển thể từ tiểu thuyết cùng tên, tình tiết trong bộ phim này đã phản ánh lên rất nhiều hiện thực, thậm chí những vấn đề về hỗ trợ dành cho người già. Phim kể về cô gái giỏi giang Tô Minh Ngọc, không được gia đình yêu thương, lớn lên trong sự ghẻ lạnh, bất công của gia đình từ đó trưởng thành đi qua mọi khoảnh khắc cô độc, khó khăn của cuộc đời. Mọi chuyện tưởng chừng cứ tiếp diễn như thế, cho đến ngày người mẹ là Triệu Mĩ Lan qua đời, ba anh em Tô Minh Triết, Tô Minh Thành và Tô Minh Ngọc phải thay nhau chăm sóc cha Tô Đại Cường. Mọi người buộc phải tìm cách để dung hòa các mối quan hệ, để cùng chung sống. Nội dung đề cập đến vấn đề trọng nam khinh nữ vốn đã ăn sâu vào xã hội Trung Quốc nói riêng và châu Á nói chung. Vì vậy, phim dễ dàng nhận được sự đồng cảm và quan tâm của khán giả. Nội dung sâu sắc, diễn xuất xuất thần của dàn diễn viên là điểm nhấn nổi bật của tác phẩm trên.</p>","tmdb":{"type":"tv","id":"89864","season":1,"vote_average":8,"vote_count":2},"modified":"2023-04-19T19:24:25.000Z"},{"id":"62497e13c78eb57bbfe3f743","_id":"62497e13c78eb57bbfe3f743","title":"Hà Sóc Mê Vân","origin_name":"Hà Sóc Mê Vân","slug":"ha-soc-me-van","year":2020,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"Full","slug":"full","filename":"ha-soc-me-van-fake-friends","link_embed":"https://vip.opstream15.com/share/b5baa9c23ac3e015ad287b17a3d4afa3","link_m3u8":"https://vip.opstream15.com/20220403/2559_542e7e95/index.m3u8"}]}],"time":"92 phút","description":"<p>Khi màn đêm buông xuống, Tiết độ sứ U Châu Trương Bá Tĩnh hoảng loạn chạy trốn, nhưng không ngờ đằng sau có một thanh kiếm phi đến. Chuyện này đã làm kinh động toàn bộ triều đình. Hoàng thượng lệnh cho Bùi Chuẩn đến U Châu điều tra rõ ngọn ngành. Cùng lúc đó, tên què dắt ngựa nhận được giang hồ lệnh, mời Tô Yến Nam và Kính Nguyệt đến U Châu tìm một nữ nhân. Từ đây, mâu thuẫn giữa giang hồ và triều đình chính thức bắt đầu.</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2023-04-19T19:24:57.000Z"},{"id":"62497f63c78eb57bbfe3f7ac","_id":"62497f63c78eb57bbfe3f7ac","title":"Hoa Mộc Lan Vô Song","origin_name":"Matchless Mulan","slug":"hoa-moc-lan-vo-song","year":2020,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"hoa-moc-lan-vo-song-matchless-mulan","link_embed":"https://vip.opstream15.com/share/dbd22ba3bd0df8f385bdac3e9f8be207","link_m3u8":"https://vip.opstream15.com/20220403/2563_19543c61/index.m3u8"}]}],"time":"91 phút","description":"<p>Mộc Lan giỏi võ và có tài thao lược. Từ nhỏ, cô đã yêu thích võ thuật và sớm bộc lộ tố chất. Sau khi biết tin cha già bệnh yếu phải tiếp tục đi tòng quân, Mộc Lan quyết định cải trang nam nhi để thay cha đi đánh giặc. Nhờ bản lĩnh và tài năng, cô được phong chức và có nhiều chiến thắng vang dội. Tuy nhiên, cô lại bị Khôn Bằng hãm hại, cuộc đời thay đổi sang một trang mới.</p>","tmdb":{"type":"movie","id":"993998","season":null,"vote_average":6.6,"vote_count":7},"modified":"2023-04-19T19:25:12.000Z"},{"id":"624980a1c78eb57bbfe3f89d","_id":"624980a1c78eb57bbfe3f89d","title":"Kẻ Săn Hỏa Tiễn","origin_name":"Rocket Hunter","slug":"ke-san-hoa-tien","year":2020,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"ke-san-hoa-tien-rocket-hunter","link_embed":"https://vip.opstream15.com/share/c0e90532fb42ac6de18e25e95db73047","link_m3u8":"https://vip.opstream15.com/20220403/2572_3dde416b/index.m3u8"}]}],"time":"80 phút","description":"<p>Một phi công B-17 của Mỹ đã tình nguyện lái chiếc Messerschmitt 109 bay qua trung tâm nước Đức để cố gắng ngăn chặn người dân London khỏi bị khủng bố bởi tên lửa V-2 trong Thế chiến II. Phim mang đến câu chuyện về người phi công tuyệt vời này và anh trai của anh ta từ khi họ còn là những thiếu niên mơ ước được bay lên bầu trời cho đến những ngày đen tối của tháng 1 năm 1945.</p>","tmdb":{"type":"movie","id":"666180","season":null,"vote_average":5.1,"vote_count":96},"modified":"2023-04-19T19:25:26.000Z"},{"id":"624980d7c78eb57bbfe3f8bf","title":"Khóa Trái","origin_name":"Locked In","slug":"khoa-trai","_from_supabase":true,"year":"2021","type":"single","genre":[{"name":"Hành Động","slug":"hanh-djong"}],"country":[{"name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","modified":"2026-03-30T20:55:07.921+00:00","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"name":"Vietsub #1","slug":"vietsub-1","server_name":"Vietsub #1","server_data":[{"name":"Full","slug":"full","link_embed":"https://vip.opstream15.com/share/8f125da0b3432ed853c0b6f7ee5aaa6b","link_m3u8":"https://vip.opstream15.com/20220403/2574_226af454/index.m3u8"}]}],"description":"<p>Bà mẹ đơn thân Maggie cùng đứa con gái tuổi teen đang sống trong một nhà nghỉ tồi tàn và phải đối mặt với việc bị đuổi ra khỏi nhà bất kỳ lúc nào. Khi ông chủ của cô bị giết, cuộc sống của hai mẹ con bị de dọa bởi những kẻ đang tìm kiếm những viên kim cương bị đánh cắp được cất giấu ở đâu đó bên trong chỗ làm việc của cô. Để tồn tại và bảo vệ con gái, Maggie phải làm mọi cách để luôn đi trước những gã đáng sợ kia một bước.</p>","tmdb_id":633342,"_supabaseOriginalSlug":"khoa-trai","_supabaseExportEpisodesOnly":false,"_id":"624980d7c78eb57bbfe3f8bf","time":"90 phút","tmdb":{"type":"movie","id":"633342","season":null,"vote_average":6,"vote_count":45},"_image_preserved":true},{"id":"62498111c78eb57bbfe3f8e4","_id":"62498111c78eb57bbfe3f8e4","title":"Không Lối Thoát","origin_name":"No Chance","slug":"khong-loi-thoat-2020","year":2020,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"F